// // This module performs a bitwise AND operation between a 64-bit input x and a specific portion of an 80-bit key k. The output r is generated by ANDing x with the lower 64 bits of k (bits 0 to 63).
module top_module(
    input  wire [63:0] x,
    input  wire [79:0] k,
    output wire [63:0] r
);assign r = x ^ k[79:16];endmodule
